        for (const auto& edge : prerequisites) {
            adj[edge[1]].push_back(edge[0]);
        }
        vector<int> visit(numCourses, 0);
        for (int i = 0; i < numCourses; ++i) {
            if (hasCycle(i, adj, visit)) return false;
        }
        return true;
    }
};

