class Solution:
    def searchRange(self, nums: List[int], target: int) -> List[int]:
        def bisect(find_left):
            lo, hi, idx = 0, len(nums) - 1, -1
            while lo <= hi:
                mid = (lo + hi) // 2
                if nums[mid] == target:
                    idx = mid
                    if find_left: hi = mid - 1
                    else: lo = mid + 1
                elif nums[mid] < target: lo = mid + 1
                else: hi = mid - 1
            return idx
        return [bisect(True), bisect(False)]

