class Solution:
    def minWindow(self, s: str, t: str) -> str:
        from collections import Counter
        need = Counter(t)
        missing = len(t)
        best = (0, float('inf'))
        j = 0
        for i, c in enumerate(s):
            if need[c] > 0:
                missing -= 1
            need[c] -= 1
            while missing == 0:
                if i - j < best[1] - best[0]:
                    best = (j, i)
                need[s[j]] += 1
                if need[s[j]] > 0:
                    missing += 1
                j += 1
        return "" if best[1] == float('inf') else s[best[0]:best[1]+1]

