                int[] cell = q.poll();
                for (int[] d : dirs) {
                    int nr = cell[0]+d[0], nc = cell[1]+d[1];
                    if (nr>=0 && nc>=0 && nr<m && nc<n && grid[nr][nc]==1) {
                        grid[nr][nc] = 2; fresh--; q.offer(new int[]{nr,nc});
                    }
                }
            }
        }
        return fresh == 0 ? mins : -1;
    }
