class Solution:
    def findTargetSumWays(self, nums: List[int], target: int) -> int:
        total = sum(nums)
        if (total - target) % 2 != 0 or total < target:
            return 0
        subset_sum = (total - target) // 2
        dp = [0]*(subset_sum + 1)
        dp[0] = 1
        for n in nums:
            for i in range(subset_sum, n - 1, -1):
                dp[i] += dp[i - n]
        return dp[subset_sum]

