class Solution:
    def wordBreak(self, s: str, wordDict: List[str]) -> List[str]:
        words = set(wordDict)
        memo = {}
        def dfs(i):
            if i in memo: return memo[i]
            if i == len(s): return [""]
            res = []
            for j in range(i + 1, len(s) + 1):
                w = s[i:j]
                if w in words:
                    sub_sentences = dfs(j)
                    for sub in sub_sentences:
                        res.append(w + ("" if not sub else " " + sub))
            memo[i] = res
            return res
        return dfs(0)

