        for (int j = i + 1; j <= s.size(); ++j) {
            string w = s.substr(i, j - i);
            if (dict.count(w)) {
                vector<string> subs = dfs(s, j);
                for (const auto& sub : subs) {
                    res.push_back(w + (sub.empty() ? "" : " " + sub));
