        List<String> res = new ArrayList<>();
        if (i == s.length()) { res.add(""); return res; }
        for (int j = i + 1; j <= s.length(); j++) {
            String w = s.substring(i, j);
            if (dict.contains(w)) {
                List<String> subs = dfs(s, j);
                for (String sub : subs) {
                    res.add(w + (sub.isEmpty() ? "" : " " + sub));
                }
            }
        }
        memo.put(i, res);
        return res;
    }
}

