class Solution {
public:
    int rob(vector<int>& nums) {
        if (nums.size() == 1) return nums[0];
        auto robLinear = [](const vector<int>& arr, int lo, int hi) {
            int a = 0, b = 0;
            for (int i = lo; i <= hi; ++i) {
                int t = max(b, a + arr[i]);
                a = b;
                b = t;
            }
            return b;
        };
        return max(robLinear(nums, 0, nums.size() - 2), robLinear(nums, 1, nums.size() - 1));
    }
};

