        while (l < n && a[l] == sorted_a[l]) l++;
        int r = n - 1;
        while (r >= 0 && a[r] == sorted_a[r]) r--;
        // reverse subarray l to r
        for (int i = 0; i <= (r - l) / 2; i++) {
            int t = a[l + i];
            a[l + i] = a[r - i];
            a[r - i] = t;
        }
        if (Arrays.equals(a, sorted_a)) System.out.println("yes\n" + (l + 1) + " " + (r + 1));
        else System.out.println("no");
    }
}

