            while (l < r && !vowels.contains(chars[l])) l++;
            while (l < r && !vowels.contains(chars[r])) r--;
            if (l < r) {
                char temp = chars[l];
                chars[l] = chars[r];
                chars[r] = temp;
                l++; r--;
            }
        }
        return new String(chars);
    }
}

