    def findMode(self, root: Optional[TreeNode]) -> List[int]:
        self.prev = None
        self.count = 0
        self.max_count = 0
        self.modes = []
        def inorder(node):
            if not node: return
            inorder(node.left)

            if node.val == self.prev:
                self.count += 1
            else:
                self.count = 1
                self.prev = node.val

            if self.count > self.max_count:
                self.max_count = self.count
                self.modes = [node.val]
            elif self.count == self.max_count:
                self.modes.append(node.val)

            inorder(node.right)
        inorder(root)
        return self.modes

