class Solution:
    def getSum(self, a: int, b: int) -> int:
        MASK = 0xFFFFFFFF
        while b != 0:
            total = (a ^ b) & MASK
            carry = ((a & b) << 1) & MASK
            a, b = total, carry
        return a if a <= 0x7FFFFFFF else ~(a ^ MASK)

