        board[r][c] = '#';
        int[][] dirs = {{1,0},{-1,0},{0,1},{0,-1}};
        for (int[] d : dirs) {
            int nr = r + d[0], nc = c + d[1];
            if (nr >= 0 && nc >= 0 && nr < m && nc < n && board[nr][nc] != '#') {
                dfs(board, nr, nc, nextNode);
            }
        }
        board[r][c] = ch;
    }
