class Solution {
public:
    ListNode* reverseKGroup(ListNode* head, int k) {
        ListNode* curr = head;
        int count = 0;
        while (curr && count < k) { curr = curr->next; count++; }
        if (count == k) {
            ListNode* prev = reverseKGroup(curr, k);
            curr = head;
            for (int i = 0; i < k; ++i) {
                ListNode* temp = curr->next;
                curr->next = prev;
                prev = curr;
                curr = temp;
            }
            return prev;
        }
        return head;
    }
};

