class Solution {
public:
    ListNode* rotateRight(ListNode* head, int k) {
        if (!head || !head->next || k == 0) return head;
        ListNode* curr = head;
        int length = 1;
        while (curr->next) { curr = curr->next; length++; }
        curr->next = head;
        k = k % length;
        int steps = length - k;
        for (int i = 0; i < steps; ++i) curr = curr->next;
        ListNode* newHead = curr->next;
        curr->next = nullptr;
        return newHead;
    }
};

