        int val = postorder.back(); postorder.pop_back();
        TreeNode* root = new TreeNode(val);
        int idx = idxMap[val];
        root->right = helper(postorder, idx + 1, inRight);
        root->left = helper(postorder, inLeft, idx - 1);
        return root;
