        if numerator == 0: return "0"
        res = []
        if (numerator < 0) ^ (denominator < 0): res.append("-")
        num, den = abs(numerator), abs(denominator)
        res.append(str(num // den))
        rem = num % den
        if rem == 0: return "".join(res)
        res.append(".")
        pos = {}
        while rem != 0:
            if rem in pos:
                res.insert(pos[rem], "(")
                res.append(")")
                break
            pos[rem] = len(res)
            rem *= 10
            res.append(str(rem // den))
            rem %= den
        return "".join(res)

