class Solution:
    def majorityElement(self, nums: List[int]) -> List[int]:
        if not nums: return []
        c1, c2, count1, count2 = None, None, 0, 0
        for n in nums:
            if n == c1:
                count1 += 1
            elif n == c2:
                count2 += 1
            elif count1 == 0:
                c1, count1 = n, 1
            elif count2 == 0:
                c2, count2 = n, 1
            else:
                count1 -= 1
                count2 -= 1
        res = []
        for c in [c1, c2]:
            if nums.count(c) > len(nums) // 3:
                res.append(c)
        return list(set(res))

