    public List<Double> averageOfLevels(TreeNode root) {
        List<Double> res = new ArrayList<>();
        Queue<TreeNode> q = new LinkedList<>();
        q.add(root);
        while (!q.isEmpty()) {
            int sz = q.size();
            double levelSum = 0;
            for (int i = 0; i < sz; i++) {
                TreeNode node = q.poll();
                levelSum += node.val;
                if (node.left != null) q.add(node.left);
                if (node.right != null) q.add(node.right);
            }
            res.add(levelSum / sz);
        }
        return res;
    }
}

