class Solution:
    def flipAndInvertImage(self, image: List[List[int]]) -> List[List[int]]:
        n = len(image)
        for r in range(n):
            left, right = 0, n - 1
            while left <= right:
                if left == right:
                    image[r][left] ^= 1
                else:
                    if image[r][left] == image[r][right]:
                        image[r][left] ^= 1
                        image[r][right] ^= 1
                left += 1
                right -= 1
        return image

