        Set<Integer> setA = new HashSet<>();
        for (int x : aliceSizes) setA.add(x);
        for (int y : bobSizes) {
            if (setA.contains(y + diff)) return new int[]{y + diff, y};
        }
        return new int[0];
    }
}

