        int l = 0, r = chars.length - 1;
        while (l < r) {
            if (!Character.isLetter(chars[l])) l++;
            else if (!Character.isLetter(chars[r])) r--;
            else {
                char t = chars[l]; chars[l] = chars[r]; chars[r] = t;
                l++; r--;
            }
        }
        return new String(chars);
    }
}

