class Solution:
    def sortArrayByParityII(self, nums: List[int]) -> List[int]:
        even, odd = 0, 1
        n = len(nums)
        while even < n and odd < n:
            if nums[even] % 2 == 1:
                # Find the next misplaced odd number index to swap
                while nums[odd] % 2 == 1:
                    odd += 2
                nums[even], nums[odd] = nums[odd], nums[even]
            even += 2
        return nums

