class Solution {
public:
    int numUniqueEmails(vector<string>& emails) {
        unordered_set<string> seen;
        for (const string& e : emails) {
            int at = e.find('@');
            string local = e.substr(0, at);
            string domain = e.substr(at);
            string cleanLocal = "";
            for (char c : local) {
                if (c == '.') continue;
                if (c == '+') break;
                cleanLocal += c;
            }
            seen.insert(cleanLocal + domain);
        }
        return seen.size();
    }
};

