            String local = e.substring(0, at);
            String domain = e.substring(at);
            StringBuilder cleanLocal = new StringBuilder();
            for (char c : local.toCharArray()) {
                if (c == '.') continue;
                if (c == '+') break;
                cleanLocal.append(c);
            }
            seen.add(cleanLocal.toString() + domain);
        }
        return seen.size();
    }
}

