import heapq
class Solution:
    def lastStoneWeight(self, stones: List[int]) -> int:
        # Max-heap using negative values
        heap = [-x for x in stones]
        heapq.heapify(heap)
        while len(heap) > 1:
            s1 = -heapq.heappop(heap)
            s2 = -heapq.heappop(heap)
            if s1 != s2:
                heapq.heappush(heap, -(s1 - s2))
        return -heap[0] if heap else 0

