        for (int x : stones) pq.add(x);
        while (pq.size() > 1) {
            int s1 = pq.poll();
            int s2 = pq.poll();
            if (s1 != s2) pq.add(s1 - s2);
        }
        return pq.isEmpty() ? 0 : pq.peek();
    }
}

