    def relativeSortArray(self, arr1: List[int], arr2: List[int]) -> List[int]:
        counts = [0] * 1001
        for x in arr1: counts[x] += 1
        res = []
        # First place elements of arr2
        for x in arr2:
            res.extend([x] * counts[x])
            counts[x] = 0
        # Then place remaining elements in ascending order
        for x in range(1001):
            if counts[x] > 0:
                res.extend([x] * counts[x])
        return res

