class Solution:
    def distanceBetweenBusStops(self, distance: List[int], start: int, destination: int) -> int:
        if start > destination:
            start, destination = destination, start
        # Clockwise distance
        d1 = sum(distance[start:destination])
        # Counter-clockwise distance
        d2 = sum(distance) - d1
        return min(d1, d2)

