class Solution {
public:
    int oddCells(int m, int n, vector<vector<int>>& indices) {
        vector<int> rows(m, 0), cols(n, 0);
        for (const auto& ind : indices) {
            rows[ind[0]] ^= 1;
            cols[ind[1]] ^= 1;
        }
        int oddR = 0, oddC = 0;
        for (int x : rows) if (x) oddR++;
        for (int x : cols) if (x) oddC++;
        return oddR * (n - oddC) + (m - oddR) * oddC;
    }
};

