    vector<int> arrayRankTransform(vector<int>& arr) {
        vector<int> sortedArr = arr;
        sort(sortedArr.begin(), sortedArr.end());
        unordered_map<int, int> ranks;
        int rank = 1;
        for (int x : sortedArr) {
            if (!ranks.count(x)) ranks[x] = rank++;
        }
