class Solution:
    def smallerNumbersThanCurrent(self, nums: List[int]) -> List[int]:
        counts = [0] * 102
        for x in nums: counts[x] += 1
        # Prefix sum
        for i in range(1, 102):
            counts[i] += counts[i - 1]
        return [counts[x - 1] if x > 0 else 0 for x in nums]

