class Solution:
    def findTheDistanceValue(self, arr1: List[int], arr2: List[int], d: int) -> int:
        arr2.sort()
        ans = 0
        for x in arr1:
            # Use binary search to find any element in range [x - d, x + d]
            low, high = 0, len(arr2) - 1
            valid = True
            while low <= high:
                mid = (low + high) // 2
                if abs(arr2[mid] - x) <= d:
                    valid = False
                    break
                elif arr2[mid] < x:
                    low = mid + 1
                else:
                    high = mid - 1
            if valid: ans += 1
        return ans

