    def finalPrices(self, prices: List[int]) -> List[int]:
        stack = []
        res = list(prices)
        for i, p in enumerate(prices):
            while stack and prices[stack[-1]] >= p:
                idx = stack.pop()
                res[idx] -= p
            stack.append(i)
        return res

