class Solution:
    def specialArray(self, nums: List[int]) -> int:
        nums.sort()
        n = len(nums)
        # Search for x in range [1, n]
        for x in range(1, n + 1):
            # Binary search first element >= x
            low, high = 0, n - 1
            idx = n
            while low <= high:
                mid = (low + high) // 2
                if nums[mid] >= x:
                    idx = mid
                    high = mid - 1
                else:
                    low = mid + 1
            if n - idx == x:
                return x
        return -1

