            int f1 = counts.get(a), f2 = counts.get(b);
            if (f1 != f2) return Integer.compare(f1, f2);
            return Integer.compare(b, a);
        });
        for (int i = 0; i < nums.length; i++) nums[i] = temp[i];
        return nums;
    }
}

