    vector<int> decrypt(vector<int>& code, int k) {
        int n = code.size();
        if (k == 0) return vector<int>(n, 0);
        vector<int> res(n, 0);
        int start = (k > 0) ? 1 : n + k;
        int end = (k > 0) ? k : n - 1;
        int curr = 0;
        for (int i = start; i <= end; ++i) curr += code[i % n];
        for (int i = 0; i < n; ++i) {
            res[i] = curr;
            curr -= code[start % n];
            start++; end++;
            curr += code[end % n];
        }
        return res;
    }
};

