class Solution {
public:
    int countConsistentStrings(string allowed, vector<string>& words) {
        vector<bool> aSet(26, false);
        for (char c : allowed) aSet[c - 'a'] = true;
        int ans = 0;
        for (const string& w : words) {
            bool ok = true;
            for (char c : w) {
                if (!aSet[c - 'a']) { ok = false; break; }
            }
            if (ok) ans++;
        }
        return ans;
    }
};

