        int n = s.length(), h1 = 0, h2 = 0;
        for (int i = 0; i < n / 2; i++) if (vowels.contains(s.charAt(i))) h1++;
        for (int i = n / 2; i < n; i++) if (vowels.contains(s.charAt(i))) h2++;
        return h1 == h2;
    }
