            return a[1] > b[1];
        });
        int ans = 0;
        for (const auto& box : boxTypes) {
            int take = min(box[0], truckSize);
            ans += take * box[1];
            truckSize -= take;
            if (truckSize == 0) break;
        }
        return ans;
    }
};

