        int maxLen = 0, count = 0;
        for (const auto& rect : rectangles) {
            int side = min(rect[0], rect[1]);
            if (side > maxLen) {
                maxLen = side;
                count = 1;
            } else if (side == maxLen) {
                count++;
            }
        }
        return count;
