class Solution:
    def countBalls(self, lowLimit: int, highLimit: int) -> int:
        boxes = {}
        for num in range(lowLimit, highLimit + 1):
            s = 0
            while num > 0:
                s += num % 10
                num //= 10
            boxes[s] = boxes.get(s, 0) + 1
        return max(boxes.values())

