class Solution:
    def minOperations(self, s: str) -> int:
        # Check operations to match pattern "010101..."
        op0 = 0
        for i, c in enumerate(s):
            if i % 2 == 0:
                if c != '0': op0 += 1
            else:
                if c != '1': op0 += 1
        # The other pattern is "101010..." which will require n - op0 operations
        return min(op0, len(s) - op0)

