class Solution {
public:
    int secondHighest(string s) {
        int m1 = -1, m2 = -1;
        for (char c : s) {
            if (isdigit(c)) {
                int val = c - '0';
                if (val > m1) { m2 = m1; m1 = val; }
                else if (val < m1 && val > m2) { m2 = val; }
            }
        }
        return m2;
    }
};

