class Solution {
    public int maxAscendingSum(int[] nums) {
        int best = nums[0], cur = nums[0];
        for (int i = 1; i < nums.length; i++) {
            if (nums[i] > nums[i-1]) cur += nums[i];
            else cur = nums[i];
            best = Math.max(best, cur);
        }
